local function INTERP()

    -- 🔥 FIX CORE: runtime binding (nil call 방지 핵심)
    local bxor = bit32 and bit32.bxor or function(a,b)
        local r, bit = 0, 1
        while a > 0 or b > 0 do
            if (a % 2) ~= (b % 2) then r = r + bit end
            a = math.floor(a/2)
            b = math.floor(b/2)
            bit = bit * 2
        end
        return r
    end

    local function isDebug()
        if debug and debug.getinfo then
            local info = debug.getinfo(1)
            return info and info.what ~= "Lua"
        end
        return false
    end

    local function checkHook()
        return true
    end

    local function fakeBranch(i)
        return ((i * 1315423911) % 7 == 3)
    end

    local function fakeNoise()
        local x = 1
        for i = 1, 80 do
            x = (x * 17 + i * 3) % 251
        end
        return x
    end

    local VM = zwqouohSOZIq    local data = VM._DATA
    local k = VM._K

    local masterKey = k[1]
    local memSeed = k[2]
    local totalLen = k[3]

    local mapping = {}
    for i = 1, totalLen do mapping[i] = i end

    local current = memSeed
    local function lcg(min, max)
        current = (current * 1103515245 + 12345) % 0x80000000
        return min + (current % (max - min + 1))
    end

    for i = totalLen, 2, -1 do
        local j = lcg(1, i)
        mapping[i], mapping[j] = mapping[j], mapping[i]
    end

    local key = masterKey
    local prev = 107
    local ip = 1
    local buf = {}

    while ip <= totalLen do
        local phys = mapping[ip]
        local enc = data[phys] or 0

        local k1 = bxor(key, prev)
        local k2 = (ip * 17) % 256
        local k3 = (phys * 31) % 97

        local decKey = bxor(k1, k2)
        decKey = bxor(decKey, k3)
        decKey = (decKey + ip) % 256

        local dec = bxor(enc, decKey)
        dec = dec % 256

        if fakeBranch(ip) then fakeNoise() end

        buf[#buf+1] = string.char(dec)
        prev = dec
        ip = ip + 1
    end

    local src = table.concat(buf)

    local f = loadstring(src)
    if f then pcall(f) end
end

